 {"id":"bd-3bxhj.6.11","title":"task(opentui-import certification tests): E2E certification pipeline script with full JSONL evidence ledger","description":"Objective: Implement end-to-end certification script that executes baseline capture, translation run, all comparators, and final verdict generation with complete structured evidence logs.\n\nAcceptance criteria:\n1. Script is CI-ready and supports shardable fixture execution.\n2. Evidence ledger includes correlation IDs, hashes, timings, and failure lineage.\n3. Replay helper can reconstruct any failed certification run from artifacts.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:34:25.962208662Z","created_by":"ubuntu","updated_at":"2026-02-24T22:20:13.578596430Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["certification","e2e","opentui-import","test"],"dependencies":[{"issue_id":"bd-3bxhj.6.11","depends_on_id":"bd-3bxhj.1.7","type":"blocks","created_at":"2026-02-24T22:20:13.578520248Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.11","depends_on_id":"bd-3bxhj.5.9","type":"blocks","created_at":"2026-02-24T21:37:59.617721389Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.11","depends_on_id":"bd-3bxhj.6","type":"parent-child","created_at":"2026-02-24T21:34:25.962208662Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.11","depends_on_id":"bd-3bxhj.6.10","type":"blocks","created_at":"2026-02-24T21:38:00.594649895Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.11","depends_on_id":"bd-3bxhj.6.13","type":"blocks","created_at":"2026-02-24T21:41:49.829206555Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.11","depends_on_id":"bd-3bxhj.6.9","type":"blocks","created_at":"2026-02-24T21:38:00.131277143Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.6.12","title":"task(opentui-import certification): Generate machine-checkable proof artifacts for semantic-preservation obligations","description":"Objective: Emit formalized proof artifacts (obligation graph, witness traces, invariant checksums) demonstrating why a translation is classified as equivalent or acceptable-improvement.\n\nAcceptance criteria:\n1. Proof artifacts link each verdict clause to concrete evidence witnesses.\n2. Artifact schema is machine-verifiable and replay-stable.\n3. Missing or invalid proof obligations force non-passing certification.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:41:31.486756458Z","created_by":"ubuntu","updated_at":"2026-02-24T21:41:48.408555529Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["opentui-import","proof-artifacts","verification"],"dependencies":[{"issue_id":"bd-3bxhj.6.12","depends_on_id":"bd-3bxhj.1.1","type":"blocks","created_at":"2026-02-24T21:41:47.025585774Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.12","depends_on_id":"bd-3bxhj.6","type":"parent-child","created_at":"2026-02-24T21:41:31.486756458Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.12","depends_on_id":"bd-3bxhj.6.3","type":"blocks","created_at":"2026-02-24T21:41:47.478944556Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.12","depends_on_id":"bd-3bxhj.6.4","type":"blocks","created_at":"2026-02-24T21:41:47.947299372Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.6.12","depends_on_id":"bd-3bxhj.6.7","type":"blocks","created_at":"2026-02-24T21:41:48.408500917Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
